sys_ws_operation.operation_script:
/**
 * @example <caption>Example request with curl using verbose syntax:</caption>
 * curl "https://INSTANCE.service-now.com/api/x_taniu_tan_core/v1/get_records_as_csv?map=%7B%22table_name%22%3A%22incident%22%2C%22table_query%22%3A%22assigned_to.managerISNOTEMPTY%22%2C%22query_limit%22%3A100%2C%22columns%22%3A%5B%7B%22destination_column_name%22%3A%22Assignee%20ID%22%2C%22source_column_name%22%3A%22assigned_to%22%7D%2C%7B%22destination_column_name%22%3A%22Short%20Description%22%2C%22source_column_name%22%3A%22short_description%22%7D%2C%7B%22destination_column_name%22%3A%22Assignee%20name%22%2C%22source_column_name%22%3A%22assigned_to.name%22%7D%2C%7B%22destination_column_name%22%3A%22Assignee%20manager%22%2C%22source_column_name%22%3A%22assigned_to.manager%22%7D%2C%7B%22destination_column_name%22%3A%22Assignee%20manager%20email%22%2C%22source_column_name%22%3A%22assigned_to.manager.email%22%7D%2C%7B%22destination_column_name%22%3A%22INC%20number%22%2C%22source_column_name%22%3A%22number%22%7D%5D%7D" \
 * --request GET \
 * --header "Accept:text/csv" \
 * --user 'admin':'admin'
 *
 * @example <caption>Example request with curl using shorthand syntax:</caption>
 * curl "https://INSTANCE.service-now.com/api/x_taniu_tan_core/v1/get_records_as_csv?map=%7B%22tn%22%3A%22incident%22%2C%22tq%22%3A%22assigned_to.managerISNOTEMPTY%22%2C%22ql%22%3A100%2C%22cols%22%3A%5B%7B%22dest%22%3A%22Assignee%20ID%22%2C%22src%22%3A%22assigned_to%22%7D%2C%7B%22dest%22%3A%22Short%20Description%22%2C%22src%22%3A%22short_description%22%7D%2C%7B%22dest%22%3A%22Assignee%20name%22%2C%22src%22%3A%22assigned_to.name%22%7D%2C%7B%22dest%22%3A%22Assignee%20manager%22%2C%22src%22%3A%22assigned_to.manager%22%7D%2C%7B%22dest%22%3A%22Assignee%20manager%20email%22%2C%22src%22%3A%22assigned_to.manager.email%22%7D%2C%7B%22dest%22%3A%22INC%20number%22%2C%22src%22%3A%22number%22%7D%5D%7D" \
 * --request GET \
 * --header "Accept:text/csv" \
 * --user 'admin':'admin'
 * 
 */
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

	var i,
		streamWriter,
		grComputer,
		tableName,
		columnHeaders,
		tableQuery,
		queryLimit,
		currentRow,
		snFieldName,
		snFieldVal,
		snFieldElement;
	var responseArr = [];
	var utf8BOM = '\uFEFF'; //Byte Order Mark for UTF-8
	var fileName = 'sn-data-export.csv';
	var mapObj = getMapObjectFromURL(request);

	mapObj = expandMinifiedMapObject(mapObj);

	if (
		!mapObj.hasOwnProperty('table_name') ||
		!mapObj.hasOwnProperty('columns')
	) {
		response.setStatus(400);
		throw new Error(
			'Unable to parse map object. Map must be provided as a URI parameter with the ' +
			'name "map". Map URI parameter must be equal to a JSON object with a node ' +
			'called "table_name" with the name of the table from which you\'d like to pull ' +
			'the returned data, and an a node called "columns" which consists of an array ' +
			'of objects, each with two nodes: "destination_column_name" and ' +
			'"source_column_name".'
		);
	}

	tableName = mapObj.table_name.toString();
	columnHeaders = getHeadersFromMap(mapObj);
	//Push the column headers into the response array as the first element, in CSV format.
	responseArr.push(columnHeaders.join(','));

	if (!gs.tableExists(tableName)) {
		response.setStatus(500);
		throw new Error(
			'Table with name ' + tableName + ' does not exist in ServiceNow, or is not ' +
			'accessible. Are you sure you\'ve entered the table name and not the label?'
		);
	}

	grComputer = new GlideRecord(tableName);

	tableQuery = (mapObj.hasOwnProperty('table_query')) ? mapObj.table_query.toString() : '';
	queryLimit = parseInt(mapObj.query_limit);

	//If query is provided, add it. Ditto for record query limit.
	if (tableQuery) {
		grComputer.addEncodedQuery(tableQuery);
	}
	if (queryLimit && queryLimit > 0) {
		grComputer.setLimit(queryLimit);
	}

	grComputer.query();

	//Here be dragons
	while (grComputer.next()) {
		//Check if user can read the found record
		if (!grComputer.canRead()) {
			gs.warn(
				'CSV Export: Record with sys_id ' + grComputer.getValue('sys_id') +
				' in table "' + tableName + '" cannot be read by the current user (' +
				gs.getUserID() + '). Skipping this record, and continuing to the next one.'
			);
			continue;
		}

		currentRow = [];

		//For each column in the map object...
		for (i = 0; i < mapObj.columns.length; i++) {
			//If map for this column is malformed, throw an error and halt.
			if (!mapObj.columns[i].hasOwnProperty('source_column_name')) {
				response.setStatus(400);
				throw new Error(
					'CSV Export: One or more columns in the export map object is missing the ' +
					'"source_column_name" property. The export process must abort.'
				);
			}
			//Get the next field name to work on
			snFieldName = mapObj.columns[i].source_column_name.toString();
			snFieldElement = grComputer.getElement(snFieldName); //Object reference

			//If user can read the value of the specified column, get it. If not, log a warning
			// but continue anyway with a blank value for this column.
			if (
				grComputer.isValidField(snFieldName.split('.')[0]) &&
				snFieldElement.canRead()
			) {
				/*
					NOTE: We are using .getElement().toString() here, instead of simply .getValue(),
					 because the former method supports arbitrarily dot-walking into several layers
					 of data, such as "assigned_to.manager.department.id" to get the assignee's
					 manager's department ID, for example.
				 */
				snFieldVal = snFieldElement.toString();
			} else {
				snFieldVal = '';
				gs.warn(
					'CSV Export: API user ' + gs.getUserID() + ' is unable to read the ' +
					'column ' + snFieldName + ' from the record in table ' + tableName +
					' with sys_id ' + grComputer.getValue('sys_id') + '. This could ' +
					'be because the field does not exist, or because the service account ' +
					'cannot read this field from the database. Exporting a blank value for ' +
					'this field, and continuing with export.'
				);
			}
			//If all is well, push the escaped value of the specified field into currentRow.
			//currentRow will be joined at the end of this for loop, at the bottom of the while.
			currentRow.push(
				escapeValueForCSV(snFieldVal)
			);
		}

		//Join the current row into csv format, and push that value into the response array.
		responseArr.push(currentRow.join(','));
	}

	response.setHeader('Content-Type', 'text/csv;charset=utf-8');
	response.setHeader('Content-disposition', 'attachment; filename=' + fileName);
	streamWriter = response.getStreamWriter();
	//Join the response array with a line-break between each comma-delimited row and write response.
	streamWriter.writeString(utf8BOM +	responseArr.join('\n'));
	response.setStatus(200);

	//Helper functions

	function escapeValueForCSV(fieldVal) {
		//Escape quotes.
		if (fieldVal.indexOf('"') >= 0) {
			fieldVal = fieldVal.replaceAll('"', '""');
		}

		//upcoming_feature: Escape commas won't be necessary once Tanium can handle quoted csv values
		if (fieldVal.indexOf(',')) {
			//fieldVal = fieldVal.replaceAll(',', '","');
			//Replace all commas with "turned comma" (U+2E32),
			fieldVal = fieldVal.replaceAll(',', ';');
		}


		//Wrap field value in quotes (eliminates need to escape commas/new-line characters).
		//fieldVal = '"' + fieldVal + '"';

		return fieldVal;
	}

	function getMapObjectFromURL(request) {
		var mapObj;
		try {
			mapObj = request.queryParams['map'];
			mapObj = mapObj[0];
			mapObj = JSON.parse(mapObj);
		} catch (ex) {
			response.setStatus(400);
			throw new Error(
				'Unable to parse map object. Map must be provided as a URI parameter with the ' +
				'name "map". Map URI parameter must be equal to a JSON object with a node ' +
				'called "table_name" with the name of the table from which you\'d like to pull ' +
				'the returned data, and an a node called "columns" which consists of an array ' +
				'of objects, each with two nodes: "destination_column_name" and ' +
				'"source_column_name". \n' +
				'Error: ' + ex.message
			);
		}
		return mapObj;
	}

	/**
	 * Parse out an array of headers from the map object passed into this SRAPI from the
	 *  URI parameter "map".
	 * @param {Object} mapObj
	 * @return {*[]} An array of Strings representing the names of the columns in the CSV that
	 * should be output from this SRAPI.
	 */
	function getHeadersFromMap(mapObj) {
		var i;
		var headersArr = [];
		var columns;
		if (mapObj.hasOwnProperty('columns')) {
			columns = mapObj.columns;
		} else {
			throw new Error(
				'Unable to parse map object. Map must be provided as a URI parameter with the ' +
				'name "map". Map URI parameter must be equal to a JSON object with a node ' +
				'called "table_name" with the name of the table from which you\'d like to pull ' +
				'the returned data, and an a node called "columns" which consists of an array ' +
				'of objects, each with two nodes: "destination_column_name" and ' +
				'"source_column_name".'
			);
		}

		for (i = 0; i < columns.length; i++) {
			//upcoming_feature: Uncomment the first line and remove the second once Tanium can support quoted CSV values
			//headersArr.push('"' + columns[i].destination_column_name.toString() + '"');
			headersArr.push(columns[i].destination_column_name.toString());
		}

		return headersArr;
	}

	/**
	 * This function takes a minified map object and expands it into a more verbose object.
	 * If the object is already verbose, it will return the object as-is.
	 *
	 * @param {{tn: string, ql: number, tq: string, cols: {src: string, dest: string}[]}|{table_query: string, table_name: string, query_limit: number, columns: {destination_column_name: string, source_column_name: string}[]}} minifiedMapObj - The minified map object to expand. This object should have the following nodes:
	 * - table_name or tn: The name of the table from which to pull data.
	 * - table_query or tq: The query to run on the table.
	 * - query_limit or ql: The maximum number of records to return.
	 * - columns or cols: An array of objects, each with two nodes:
	 *    - destination_column_name or dest
	 *    - source_column_name or src
	 *
	 * Example:
	 *
	 * {
	 * 	"tn" : "incident",
	 * 	"tq" : "assigned_to.managerISNOTEMPTY",
	 * 	"ql" : 100,
	 * 	"cols" : [
	 * 		{
	 * 			"dest" : "Assignee ID",
	 * 			"src" : "assigned_to"
	 * 		},
	 * 		{
	 * 			"dest" : "Short Description",
	 * 			"src" : "short_description"
	 * 		},
	 * 		{
	 * 			"dest" : "Assignee name",
	 * 			"src" : "assigned_to.name"
	 * 		},
	 * 		{
	 * 			"dest" : "Assignee manager",
	 * 			"src" : "assigned_to.manager"
	 * 		},
	 * 		{
	 * 			"dest" : "Assignee manager email",
	 * 			"src" : "assigned_to.manager.email"
	 * 		},
	 * 		{
	 * 			"dest" : "INC number",
	 * 			"src" : "number"
	 * 		}
	 * 	]
	 * }
	 *
	 * @returns {{table_query: string, table_name: string, query_limit: number, columns: {destination_column_name: string, source_column_name: string}[]}}
	 *
	 * @example
	 * var objMap = {
	 *    "tn" : "incident",
	 *    "tq" : "assigned_to.managerISNOTEMPTY",
	 *    "ql" : 100,
	 *    "cols" : [
	 *       {
	 *          "dest" : "Assignee ID",
	 *          "src" : "assigned_to"
	 *       },
	 *       {
	 *          "dest" : "Assignee name",
	 *          "src" : "assigned_to.name"
	 *       },
	 *       {
	 *          "dest" : "Assignee manager",
	 *          "src" : "assigned_to.manager"
	 *       },
	 *       {
	 *          "dest" : "Assignee manager email",
	 *          "src" : "assigned_to.manager.email"
	 *       },
	 *       {
	 *          "dest" : "INC number",
	 *          "src" : "number"
	 *       }
	 *    ]
	 * };
	 *
	 * gs.info(
	 * 	JSON.stringify(
	 * 		expandMinifiedMapObject(objMap),
	 * 		null,
	 * 		2
	 * 	)
	 * );
	 *
	 * Output:
	 *  {
	 *    "table_name": "incident",
	 *    "table_query": "assigned_to.managerISNOTEMPTY",
	 *    "query_limit": 100,
	 *    "columns": [
	 *      {
	 *        "destination_column_name": "Assignee ID",
	 *        "source_column_name": "assigned_to"
	 *      },
	 *      {
	 *        "destination_column_name": "Assignee name",
	 *        "source_column_name": "assigned_to.name"
	 *      },
	 *      {
	 *        "destination_column_name": "Assignee manager",
	 *        "source_column_name": "assigned_to.manager"
	 *      },
	 *      {
	 *        "destination_column_name": "Assignee manager email",
	 *        "source_column_name": "assigned_to.manager.email"
	 *      },
	 *      {
	 *        "destination_column_name": "INC number",
	 *        "source_column_name": "number"
	 *      }
	 *    ]
	 *  }
	 *
	 *  @example
	 *
	 */
	function expandMinifiedMapObject(minifiedMapObj) {
		/*
		This function takes a minified map object and expands it into a more verbose object.
		If the object is already verbose, it will return the object as-is.

		Example minified map object:
		{
			"tn" : "incident",
			"tq" : "assigned_to.managerISNOTEMPTY",
			"ql" : 100,
			"cols" : [
				{
					"dest" : "Assignee ID",
					"src" : "assigned_to"
				},
				{
					"dest" : "Short Description",
					"src" : "short_description"
				},
				{
					"dest" : "Assignee name",
					"src" : "assigned_to.name"
				},
				{
					"dest" : "Assignee manager",
					"src" : "assigned_to.manager"
				},
				{
					"dest" : "Assignee manager email",
					"src" : "assigned_to.manager.email"
				},
				{
					"dest" : "INC number",
					"src" : "number"
				}
			]
		}

		Example expanded map object:
		{
			"table_name" : "incident",
			"table_query" : "assigned_to.managerISNOTEMPTY",
			"query_limit" : 100,
			"columns" : [
				{
					"destination_column_name" : "Assignee ID",
					"source_column_name" : "assigned_to"
				},
				{
					"destination_column_name" : "Short Description",
					"source_column_name" : "short_description"
				},
				{
					"destination_column_name" : "Assignee name",
					"source_column_name" : "assigned_to.name"
				},
				{
					"destination_column_name" : "Assignee manager",
					"source_column_name" : "assigned_to.manager"
				},
				{
					"destination_column_name" : "Assignee manager email",
					"source_column_name" : "assigned_to.manager.email"
				},
				{
					"destination_column_name" : "INC number",
					"source_column_name" : "number"
				}
			]
		}
		*/
		var iCol, currentColumn, expandedCurrentColumn, columnNodeName;
		var expandedMapObj = {};
		var statusObj = {
			'success': true,
			'errors': []
		};

		if (minifiedMapObj.hasOwnProperty('tn')) {
			expandedMapObj.table_name = minifiedMapObj.tn;
		} else if (minifiedMapObj.hasOwnProperty('table_name')) {
			expandedMapObj.table_name = minifiedMapObj.table_name;
		} else {
			//Add error to log, but continue. This error will be caught by the calling function.
			statusObj.success = false;
			statusObj.errors.push(
				'When generating CSV file, the object in the `map` URL query parameter is missing the table name. Neither `tn` nor `table_name` nodes were found.'
			);
		}

		if (minifiedMapObj.hasOwnProperty('tq')) {
			expandedMapObj.table_query = minifiedMapObj.tq;
		} else if (minifiedMapObj.hasOwnProperty('table_query')) {
			expandedMapObj.table_query = minifiedMapObj.table_query;
		} else {
			//Add error to log, but continue. This error will be caught by the calling function.
			statusObj.success = false;
			statusObj.errors.push(
				'When generating CSV file, the object in the `map` URL query parameter is missing the table query. Neither `tq` nor `table_query` nodes were found.'
			);
		}

		if (minifiedMapObj.hasOwnProperty('ql')) {
			expandedMapObj.query_limit = minifiedMapObj.ql;
		} else if (minifiedMapObj.hasOwnProperty('query_limit')) {
			expandedMapObj.query_limit = minifiedMapObj.query_limit;
		}

		expandedMapObj.columns = [];
		columnNodeName = minifiedMapObj.hasOwnProperty('cols') ? 'cols' : 'columns';

		for (iCol = 0; iCol < minifiedMapObj[columnNodeName].length; iCol++) {
			currentColumn = minifiedMapObj[columnNodeName][iCol];
			expandedCurrentColumn = {};

			//If the column has a `dest` node, use that. Otherwise, use `destination_column_name`.
			if (currentColumn.hasOwnProperty('dest')) {
				expandedCurrentColumn.destination_column_name = currentColumn.dest;
			} else if (currentColumn.hasOwnProperty('destination_column_name')) {
				expandedCurrentColumn.destination_column_name = currentColumn.destination_column_name;
			}

			//If the column has a `src` node, use that. Otherwise, use `source_column_name`.
			if (currentColumn.hasOwnProperty('src')) {
				expandedCurrentColumn.source_column_name = currentColumn.src;
			} else if (currentColumn.hasOwnProperty('source_column_name')) {
				expandedCurrentColumn.source_column_name = currentColumn.source_column_name;
			}

			if (
				expandedCurrentColumn.hasOwnProperty('destination_column_name') &&
				expandedCurrentColumn.hasOwnProperty('source_column_name') &&
				expandedCurrentColumn.destination_column_name &&
				expandedCurrentColumn.source_column_name
			) {
				expandedMapObj.columns.push(expandedCurrentColumn);
			} else {
				//Add error to log, but continue. This error will be caught by the calling function.
				statusObj.success = false;
				statusObj.errors.push(
					'When generating CSV file, one or more columns in the `map` URL query ' +
					'parameter is missing either the source or destination column name. \n' +
					'Column: \n' + JSON.stringify(currentColumn, null, 2)
				);
			}
		}

		if (!statusObj.success) {
			gs.error(
				'Errors were encountered while expanding the minified map object. ' +
				'The expanded map object may be missing required nodes. \n\nErrors: \n' +
				JSON.stringify(errors, null, 2)
			);
		}

		return expandedMapObj;
	}

	/*
	DOCUMENTATION:
		https://snprotips.com/blog/2022/2/7/how-to-return-a-csv-file-from-a-servicenow-scripted-rest-api

	Example request URL:
		https://${USERNAME}:${PASSWORD}@${INSTANCE}.service-now.com/api/x_taniu_tan_core/v1/get_records_as_csv?map=%7B%20%22table_name%22%20%3A%20%22incident%22%2C%20%22table_query%22%20%3A%20%22assigned_to.managerISNOTEMPTY%22%2C%20%22query_limit%22%20%3A%20100%2C%20%22columns%22%20%3A%20%5B%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20ID%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20mame%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to.name%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20manager%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to.manager%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22Assignee%20manager%20email%22%2C%20%22source_column_name%22%20%3A%20%22assigned_to.manager.email%22%20%7D%2C%20%7B%20%22destination_column_name%22%20%3A%20%22INC%20number%22%2C%20%22source_column_name%22%20%3A%20%22number%22%20%7D%20%5D%20%7D
	 */

	/*
	Fully expanded object in the example URL above:
	{
		"table_name" : "incident",
		"table_query" : "assigned_to.manager.emailISNOTEMPTY",
		"query_limit" : 100,
		"columns" : [
			{
				"destination_column_name" : "Assignee ID",
				"source_column_name" : "assigned_to"
			},
			{
				"destination_column_name" : "Assignee mame",
				"source_column_name" : "assigned_to.name"
			},
			{
				"destination_column_name" : "Assignee manager",
				"source_column_name" : "assigned_to.manager.name"
			},
			{
				"destination_column_name" : "Assignee manager email",
				"source_column_name" : "assigned_to.manager.email"
			},
			{
				"destination_column_name" : "INC number",
				"source_column_name" : "number"
			}
		]
	}
	*/
})(request, response);
